
UPDATE public.items SET category='dairy' WHERE category!='dairy' AND (name ILIKE '%milk%' OR name ILIKE '%paneer%' OR name ILIKE '%curd%' OR name ILIKE '%dahi%' OR name ILIKE '%butter%' OR name ILIKE '%ghee%' OR name ILIKE '%cheese%' OR name ILIKE '%yogurt%' OR name ILIKE '%lassi%' OR name ILIKE '%cream%' OR sub ILIKE 'Dairy');
UPDATE public.items SET category='vegetable' WHERE category!='vegetable' AND (name ILIKE '%vegetable%' OR name ILIKE '%peas%' OR name ILIKE '%tomato%' OR name ILIKE '%onion%' OR name ILIKE '%potato%' OR name ILIKE '%spinach%' OR name ILIKE '%palak%' OR name ILIKE '%carrot%' OR name ILIKE '%cabbage%' OR name ILIKE '%cauliflower%' OR name ILIKE '%gobi%' OR name ILIKE '%bhindi%' OR name ILIKE '%lauki%' OR name ILIKE '%fruit%' OR name ILIKE '%banana%' OR name ILIKE '%apple%' OR name ILIKE '%mango%');
UPDATE public.items SET category='hygiene' WHERE category!='hygiene' AND (name ILIKE '%soap%' OR name ILIKE '%shampoo%' OR name ILIKE '%toothpaste%' OR name ILIKE '%brush%' OR name ILIKE '%sanitary%' OR name ILIKE '%handwash%' OR name ILIKE '%bodywash%' OR name ILIKE '%deodorant%' OR name ILIKE '%lotion%' OR name ILIKE '%face wash%');
UPDATE public.items SET category='household' WHERE category!='household' AND (name ILIKE '%detergent%' OR name ILIKE '%surf%' OR name ILIKE '%phenyl%' OR name ILIKE '%cleaner%' OR name ILIKE '%broom%' OR name ILIKE '%harpic%' OR name ILIKE '%lizol%' OR name ILIKE '%vim%' OR name ILIKE '%tissue%' OR name ILIKE '%napkin%' OR name ILIKE '%garbage%' OR name ILIKE '%mosquito%');
UPDATE public.items SET category='medicine' WHERE category!='medicine' AND (name ILIKE '%tablet%' OR name ILIKE '%syrup%' OR name ILIKE '%capsule%' OR name ILIKE '%paracetamol%' OR name ILIKE '%crocin%' OR name ILIKE '%dolo%' OR name ILIKE '%ointment%' OR name ILIKE '%bandage%');
UPDATE public.items SET sub='Milk' WHERE name ILIKE '%milk%' AND sub IN ('Other','Dairy');
UPDATE public.items SET sub='Paneer' WHERE name ILIKE '%paneer%' AND sub IN ('Other','Dairy');
